const ids = items.map(i => `'${String(i.json.sale_id).replace(/'/g, "\\'")}'`);
if (!ids.length) {
  return [{ json: { sale_ids_csv: "'__none__'" } }];
}
return [{ json: { sale_ids_csv: ids.join(',') } }];

const headers = $items('Filter Ready Sales').map(i => i.json);
const lines = items.map(i => i.json);

const bySale = new Map();
for (const h of headers) {
  bySale.set(String(h.sale_id), {
    sale_id: String(h.sale_id),
    sale_number: String(h.sale_number),
    invoice_payload: {
      Type: 'ACCREC',
      Date: h.invoice_date_local,
      DueDate: h.invoice_date_local,
      Reference: h.reference,
      LineAmountTypes: 'Inclusive',
      Status: 'AUTHORISED',
      Contact: { Name: h.contact_name || 'Walk-in Receipts' },
      LineItems: []
    }
  });
}

for (const l of lines) {
  const key = String(l.sale_id);
  if (!bySale.has(key)) continue;
  bySale.get(key).invoice_payload.LineItems.push({
    Description: l.line_description,
    Quantity: Number(l.quantity || 1),
    UnitAmount: Number(l.line_total),
    AccountCode: '200',
    TaxType: 'OUTPUT'
  });
}

return [...bySale.values()].map(v => ({ json: v }));

const src = $items('Build Invoice Payloads');
return items.map((it, idx) => {
  const s = src[idx]?.json || {};
  const inv = it.json?.Invoices?.[0] || {};
  return {
    json: {
      sale_id: String(s.sale_id || ''),
      sale_number: String(s.sale_number || ''),
      xero_invoice_id: inv.InvoiceID || null
    }
  };
});

const invoices = $items('Normalize Invoice Response').map(i => i.json);
const invoiceBySale = new Map(invoices.map(i => [String(i.sale_id), i.xero_invoice_id]));

const accountMap = {
  fresha_eftpos_clearing: 'REPLACE_XERO_ACCOUNT_ID_EFTPOS',
  deposits_clearing: 'REPLACE_XERO_ACCOUNT_ID_DEPOSITS',
  gift_voucher_clearing: 'REPLACE_XERO_ACCOUNT_ID_GIFTVOUCHER',
  cash_clearing: 'REPLACE_XERO_ACCOUNT_ID_CASH'
};

const out = [];
for (const row of items.map(i => i.json)) {
  const saleId = String(row.sale_id);
  const invoiceId = invoiceBySale.get(saleId);
  if (!invoiceId) continue;

  out.push({
    json: {
      sale_id: saleId,
      payment_no: String(row.payment_no),
      xero_invoice_id: invoiceId,
      payment_payload: {
        Invoice: { InvoiceID: invoiceId },
        Account: { AccountID: accountMap[row.clearing_bucket] || accountMap.fresha_eftpos_clearing },
        Date: row.payment_date_local,
        Amount: Number(row.payment_amount),
        Reference: `Fresha payment ${row.payment_no}`
      }
    }
  });
}

return out;

const src = $items('Build Payment Payloads');
return items.map((it, idx) => {
  const s = src[idx]?.json || {};
  const p = it.json?.Payments?.[0] || {};
  return {
    json: {
      sale_id: s.sale_id,
      payment_no: s.payment_no,
      xero_invoice_id: s.xero_invoice_id,
      xero_payment_id: p.PaymentID || null,
      synced_at: new Date().toISOString()
    }
  };
});
